import pytest
from pydantic import ValidationError
from app.schemas import UserResponse, UserCreate
from app.services.user_service import UserService

def test_userresponse_schema_accepts_vip_boolean_and_optional():
    # vip present as True
    user = UserResponse(id=1, name="Test User", email="test@example.com", vip=True)
    assert user.vip is True
    # vip present as False
    user = UserResponse(id=2, name="Test User 2", email="test2@example.com", vip=False)
    assert user.vip is False
    # vip omitted (should be optional)
    user = UserResponse(id=3, name="Test User 3", email="test3@example.com")
    assert not hasattr(user, "vip") or user.vip is None

def test_userresponse_serialization_and_deserialization_with_and_without_vip():
    # With vip
    user = UserResponse(id=1, name="Ana Silva", email="ana@example.com", vip=True)
    json_data = user.model_dump_json()
    user2 = UserResponse.model_validate_json(json_data)
    assert user2.vip is True
    assert user2.id == user.id
    # Without vip
    user_no_vip = UserResponse(id=2, name="Bruno Lima", email="bruno@example.com")
    json_data_no_vip = user_no_vip.model_dump_json()
    user2_no_vip = UserResponse.model_validate_json(json_data_no_vip)
    assert not hasattr(user2_no_vip, "vip") or user2_no_vip.vip is None
    assert user2_no_vip.id == user_no_vip.id

def test_create_user_with_vip_field_manipulated_correctly():
    service = UserService()
    # Create user with vip True
    user_create = UserCreate(name="Vip User", email="vipuser@example.com")
    user = service.create_user(user_create, vip=True)
    assert user.vip is True
    # Create user with vip False
    user2 = service.create_user(user_create, vip=False)
    assert user2.vip is False
    # Create user without vip (should default to False or None)
    user3 = service.create_user(user_create)
    assert user3.vip is False or user3.vip is None

def test_update_user_vip_field_reflects_correctly():
    service = UserService()
    user_create = UserCreate(name="Update Vip", email="updatevip@example.com")
    user = service.create_user(user_create, vip=False)
    user_updated = service.update_user_vip(user.id, True)
    assert user_updated.vip is True
    # Update back to False
    user_updated2 = service.update_user_vip(user.id, False)
    assert user_updated2.vip is False

@pytest.mark.parametrize("invalid_vip", ["yes", 1, 0, "true", None, [], {}])
def test_user_create_rejects_invalid_vip_values(invalid_vip):
    # vip should be boolean if provided, else error
    with pytest.raises(ValidationError):
        UserResponse(id=1, name="Invalid Vip", email="invalid@example.com", vip=invalid_vip)
