package com.repoalvo.javaapi;

import com.repoalvo.javaapi.model.UserCreateRequest;
import com.repoalvo.javaapi.model.UserResponse;
import com.repoalvo.javaapi.service.UserService;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.util.List;

import static org.assertj.core.api.Assertions.assertThat;

class UserServiceUnitTest {

    private UserService userService;

    @BeforeEach
    void setup() {
        userService = new UserService();
    }

    @Test
    void createUser_shouldSetVipFieldCorrectly_whenVipProvided() {
        UserCreateRequest requestVipTrue = new UserCreateRequest("VipUserTrue", "viptrue@example.com", true);
        UserResponse userTrue = userService.create(requestVipTrue);
        assertThat(userTrue).isNotNull();
        assertThat(userTrue.vip()).isTrue();

        UserCreateRequest requestVipFalse = new UserCreateRequest("VipUserFalse", "vipfalse@example.com", false);
        UserResponse userFalse = userService.create(requestVipFalse);
        assertThat(userFalse).isNotNull();
        assertThat(userFalse.vip()).isFalse();
    }

    @Test
    void createUser_shouldSetVipFieldToDefault_whenVipNotProvided() {
        UserCreateRequest requestNoVip = new UserCreateRequest("NoVipUser", "novip@example.com", null);
        UserResponse user = userService.create(requestNoVip);
        assertThat(user).isNotNull();
        // Assuming vip is optional and defaults to false if null
        assertThat(user.vip()).isFalse();
    }

    @Test
    void updateUser_shouldReflectVipFieldChangeCorrectly() {
        UserCreateRequest request = new UserCreateRequest("UpdateVipUser", "updatevip@example.com", false);
        UserResponse created = userService.create(request);
        assertThat(created.vip()).isFalse();

        UserResponse updated = userService.updateVip(created.id(), true);
        assertThat(updated.vip()).isTrue();

        UserResponse updatedBack = userService.updateVip(created.id(), false);
        assertThat(updatedBack.vip()).isFalse();
    }

    @Test
    void listUsers_shouldIncludeVipFieldCorrectly() {
        List<UserResponse> users = userService.listAllUsers();
        assertThat(users).isNotEmpty();
        for (UserResponse user : users) {
            assertThat(user.vip()).isNotNull();
        }
    }

    @Test
    void createUser_shouldRejectInvalidVipValues() {
        // Since Java is strongly typed, invalid vip values won't compile.
        // This test ensures that null is handled and vip is Boolean type.
        UserCreateRequest requestNullVip = new UserCreateRequest("NullVipUser", "nullvip@example.com", null);
        UserResponse user = userService.create(requestNullVip);
        assertThat(user.vip()).isFalse(); // Assuming default false
    }
}
