package com.repoalvo.javaapi.model;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.Test;

import java.util.Objects;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

class UserResponseTest {

    private final ObjectMapper objectMapper = new ObjectMapper();

    @Test
    void shouldCreateUserResponseWithRoleAdminSetsVipTrue() {
        UserResponse user = new UserResponse(
                1,
                "Admin User",
                "admin@example.com",
                "ACTIVE",
                "ADMIN",
                "+55 11 90000-0000"
        );

        assertThat(user.vip()).isTrue();
    }

    @Test
    void shouldCreateUserResponseWithRoleNonAdminSetsVipFalse() {
        UserResponse user = new UserResponse(
                2,
                "Regular User",
                "user@example.com",
                "ACTIVE",
                "USER",
                "+55 11 90000-0001"
        );

        assertThat(user.vip()).isFalse();
    }

    @Test
    void shouldCreateUserResponseUsingOldConstructorSetsVipFalse() {
        UserResponse user = new UserResponse(
                3,
                "Old Constructor User",
                "olduser@example.com",
                "ACTIVE",
                "USER"
        );

        assertThat(user.phoneNumber()).isNull();
        assertThat(user.vip()).isFalse();
    }

    @Test
    void shouldSerializeUserResponseWithVipTrueAndFalse() throws JsonProcessingException {
        UserResponse adminUser = new UserResponse(
                4,
                "Admin Serialize",
                "adminserialize@example.com",
                "ACTIVE",
                "ADMIN",
                "+55 11 90000-0002"
        );

        UserResponse regularUser = new UserResponse(
                5,
                "User Serialize",
                "userserialize@example.com",
                "ACTIVE",
                "USER",
                "+55 11 90000-0003"
        );

        String adminJson = objectMapper.writeValueAsString(adminUser);
        String userJson = objectMapper.writeValueAsString(regularUser);

        assertThat(adminJson).contains("\"vip\":true");
        assertThat(userJson).contains("\"vip\":false");
    }

    @Test
    void shouldDeserializeUserResponseWithVipFieldPresent() throws JsonProcessingException {
        String jsonWithVipTrue = """
                {
                  "id": 10,
                  "name": "Deserialize Admin",
                  "email": "deserializeadmin@example.com",
                  "status": "ACTIVE",
                  "role": "ADMIN",
                  "phoneNumber": "+55 11 90000-0004",
                  "vip": true
                }
                """;

        UserResponse user = objectMapper.readValue(jsonWithVipTrue, UserResponse.class);
        assertThat(user.vip()).isTrue();
        assertThat(user.role()).isEqualTo("ADMIN");

        String jsonWithVipFalse = """
                {
                  "id": 11,
                  "name": "Deserialize User",
                  "email": "deserializeuser@example.com",
                  "status": "ACTIVE",
                  "role": "USER",
                  "phoneNumber": "+55 11 90000-0005",
                  "vip": false
                }
                """;

        UserResponse user2 = objectMapper.readValue(jsonWithVipFalse, UserResponse.class);
        assertThat(user2.vip()).isFalse();
        assertThat(user2.role()).isEqualTo("USER");
    }

    @Test
    void shouldDeserializeUserResponseWithoutVipFieldSetsVipAccordingToRole() throws JsonProcessingException {
        String jsonWithoutVipAdmin = """
                {
                  "id": 12,
                  "name": "No Vip Admin",
                  "email": "novipadmin@example.com",
                  "status": "ACTIVE",
                  "role": "ADMIN",
                  "phoneNumber": "+55 11 90000-0006"
                }
                """;

        UserResponse userAdmin = objectMapper.readValue(jsonWithoutVipAdmin, UserResponse.class);
        // Because vip is set in constructor based on role, it should be true
        assertThat(userAdmin.vip()).isTrue();

        String jsonWithoutVipUser = """
                {
                  "id": 13,
                  "name": "No Vip User",
                  "email": "novipuser@example.com",
                  "status": "ACTIVE",
                  "role": "USER",
                  "phoneNumber": "+55 11 90000-0007"
                }
                """;

        UserResponse userUser = objectMapper.readValue(jsonWithoutVipUser, UserResponse.class);
        assertThat(userUser.vip()).isFalse();
    }

    @Test
    void shouldSetVipFalseWhenRoleIsNull() {
        UserResponse user = new UserResponse(
                14,
                "Null Role User",
                "nullrole@example.com",
                "ACTIVE",
                null,
                "+55 11 90000-0008"
        );

        assertThat(user.vip()).isFalse();
    }

    @Test
    void shouldSetVipFalseWhenRoleIsUnexpectedValue() {
        UserResponse user = new UserResponse(
                15,
                "Unexpected Role User",
                "unexpectedrole@example.com",
                "ACTIVE",
                "SUPERUSER",
                "+55 11 90000-0009"
        );

        assertThat(user.vip()).isFalse();
    }

    @Test
    void equalsHashCodeAndToStringShouldIncludeVipField() {
        UserResponse user1 = new UserResponse(
                16,
                "User One",
                "userone@example.com",
                "ACTIVE",
                "ADMIN",
                "+55 11 90000-0010"
        );

        UserResponse user2 = new UserResponse(
                16,
                "User One",
                "userone@example.com",
                "ACTIVE",
                "ADMIN",
                "+55 11 90000-0010"
        );

        UserResponse user3 = new UserResponse(
                16,
                "User One",
                "userone@example.com",
                "ACTIVE",
                "USER",
                "+55 11 90000-0010"
        );

        // user1 and user2 have same vip (true), should be equal
        assertThat(user1).isEqualTo(user2);
        assertThat(user1.hashCode()).isEqualTo(user2.hashCode());
        assertThat(user1.toString()).contains("vip=true");

        // user3 has different vip (false), should not be equal to user1
        assertThat(user1).isNotEqualTo(user3);
        assertThat(user1.hashCode()).isNotEqualTo(user3.hashCode());
        assertThat(user3.toString()).contains("vip=false");
    }

    @Test
    void shouldNotAllowVipFieldModificationAfterCreation() {
        UserResponse user = new UserResponse(
                17,
                "Immutable User",
                "immutable@example.com",
                "ACTIVE",
                "ADMIN",
                "+55 11 90000-0011"
        );

        // Since UserResponse is a record, fields are final and no setters exist.
        // This test ensures immutability by compilation, so just assert vip value.
        assertThat(user.vip()).isTrue();
    }

    @Test
    void shouldSerializeJsonIncludingVipWhenPhoneNumberIsNull() throws JsonProcessingException {
        UserResponse user = new UserResponse(
                18,
                "Null Phone User",
                "nullphone@example.com",
                "ACTIVE",
                "ADMIN",
                null
        );

        String json = objectMapper.writeValueAsString(user);

        assertThat(json).contains("\"phoneNumber\":null");
        assertThat(json).contains("\"vip\":true");
    }

    @Test
    void shouldDeserializeJsonWithExtraUnexpectedFieldsWithoutAffectingVip() throws JsonProcessingException {
        String jsonWithExtraFields = """
                {
                  "id": 19,
                  "name": "Extra Fields User",
                  "email": "extrafields@example.com",
                  "status": "ACTIVE",
                  "role": "ADMIN",
                  "phoneNumber": "+55 11 90000-0012",
                  "vip": true,
                  "extraField1": "extraValue",
                  "extraField2": 12345
                }
                """;

        UserResponse user = objectMapper.readValue(jsonWithExtraFields, UserResponse.class);
        assertThat(user.vip()).isTrue();
        assertThat(user.role()).isEqualTo("ADMIN");
    }

    @Test
    void shouldThrowExceptionWhenDeserializingInvalidJson() {
        String invalidJson = """
                {
                  "id": "notAnInt",
                  "name": "Invalid User",
                  "email": "invalid@example.com",
                  "status": "ACTIVE",
                  "role": "ADMIN",
                  "phoneNumber": "+55 11 90000-0013",
                  "vip": true
                }
                """;

        assertThatThrownBy(() -> objectMapper.readValue(invalidJson, UserResponse.class))
                .isInstanceOf(JsonProcessingException.class);
    }

    @Test
    void shouldCreateUserResponseWithExtremePhoneNumberValuesWithoutAffectingVip() {
        UserResponse userEmptyPhone = new UserResponse(
                20,
                "Empty Phone",
                "emptyphone@example.com",
                "ACTIVE",
                "USER",
                ""
        );
        assertThat(userEmptyPhone.vip()).isFalse();

        String longPhone = "1234567890123456789012345678901234567890";
        UserResponse userLongPhone = new UserResponse(
                21,
                "Long Phone",
                "longphone@example.com",
                "ACTIVE",
                "ADMIN",
                longPhone
        );
        assertThat(userLongPhone.vip()).isTrue();
    }
}
